#!/usr/bin/env python3
"""generate_oncall_routing.py — derive PagerDuty routing from the service catalog."""
import yaml, json
from pathlib import Path


def load_catalog(path: str = "service-catalog.yaml") -> list[dict]:
    with open(path) as f:
        return yaml.safe_load(f)["services"]


def generate_pagerduty_routing(catalog: list[dict]) -> dict:
    """Produce a PagerDuty-compatible routing rules object from the catalog."""
    routing_rules = []
    for svc in catalog:
        for path in svc.get("codeowners_paths", []):
            # Strip inline comments (e.g. "shared/tool-schemas/  # consumer")
            clean_path = path.split("#")[0].strip()
            routing_rules.append({
                "condition": {
                    "operator": "contains",
                    "path": "alert.details.affected_path",
                    "value": clean_path,
                },
                "actions": [{
                    "type": "route",
                    "target": svc["oncall_rotation"],
                    "escalation_policy": {
                        "primary": svc["team"],
                        "secondary": svc.get("tech_lead"),
                        "tertiary": "all-ai-oncall-bridge",
                        "timeout_minutes": 30,
                    }
                }]
            })
    return {"routing_rules": routing_rules}


def generate_codeowners(catalog: list[dict]) -> str:
    """Generate .github/CODEOWNERS content from the service catalog."""
    lines = [
        "# .github/CODEOWNERS",
        "# Auto-generated from service-catalog.yaml — do not edit by hand.",
        "# Run scripts/generate_oncall_routing.py to regenerate.",
        "",
    ]
    for svc in catalog:
        lines.append(f"# --- {svc['name']} ({svc['team']}) ---")
        for path in svc.get("codeowners_paths", []):
            clean_path = path.split("#")[0].strip()
            owners = svc["team"]
            if svc.get("safety_reviewer"):
                owners += f"  {svc['safety_reviewer']}"
            lines.append(f"{clean_path:<45} {owners}")
        lines.append("")
    return "\n".join(lines)


if __name__ == "__main__":
    catalog = load_catalog()

    # Write CODEOWNERS
    codeowners_path = Path(".github/CODEOWNERS")
    codeowners_path.write_text(generate_codeowners(catalog))
    print(f"Updated {codeowners_path}")

    # Write PagerDuty routing rules
    routing = generate_pagerduty_routing(catalog)
    routing_path = Path("infra/pagerduty-routing.json")
    routing_path.write_text(json.dumps(routing, indent=2))
    print(f"Updated {routing_path}")

#!/usr/bin/env python3
"""audit_oncall_alignment.py — detect CODEOWNERS vs on-call rotation gaps."""
import yaml, subprocess, sys
from pathlib import Path


def load_catalog(path: str = "service-catalog.yaml") -> list[dict]:
    with open(path) as f:
        return yaml.safe_load(f)["services"]


def get_pd_rotation_members(rotation_name: str) -> set[str]:
    """Query PagerDuty for members of a given on-call schedule (requires PD_TOKEN env var)."""
    try:
        result = subprocess.run(
            ["curl", "-s", "-H", "Authorization: Token token=${PD_TOKEN}",
             f"https://api.pagerduty.com/schedules?query={rotation_name}"],
            capture_output=True, text=True, check=True
        )
        import json
        data = json.loads(result.stdout)
        members = set()
        for schedule in data.get("schedules", []):
            for layer in schedule.get("schedule_layers", []):
                for user in layer.get("users", []):
                    members.add(user.get("summary", "").lower())
        return members
    except Exception as e:
        print(f"WARNING: Could not query PagerDuty for {rotation_name}: {e}")
        return set()


def audit_alignment(catalog: list[dict]) -> list[str]:
    issues = []
    for svc in catalog:
        rotation = svc.get("oncall_rotation")
        if not rotation:
            issues.append(f"{svc['name']}: no oncall_rotation in service catalog")
            continue

        # Check the CODEOWNERS file references this team
        codeowners = Path(".github/CODEOWNERS").read_text()
        team = svc["team"].lstrip("@")
        if team not in codeowners:
            issues.append(f"{svc['name']}: team {svc['team']} not found in CODEOWNERS")

        # Could extend here to query PagerDuty API for rotation membership
        # and cross-reference with the GitHub team membership

    return issues


if __name__ == "__main__":
    catalog = load_catalog()
    issues = audit_alignment(catalog)

    if issues:
        print(f"ALIGNMENT ISSUES ({len(issues)}):")
        for issue in issues:
            print(f"  - {issue}")
        sys.exit(1)

    print(f"OK: all {len(catalog)} services have aligned CODEOWNERS and on-call rotations")

#!/usr/bin/env python3
"""measure_alignment.py — compute domain expertise match from incident logs + git history."""
import subprocess, json
from pathlib import Path
from datetime import datetime, timedelta
from collections import defaultdict


def get_recent_commits(path: str, days: int = 90) -> list[dict]:
    """Return commits touching the given path in the last N days."""
    since = (datetime.now() - timedelta(days=days)).strftime("%Y-%m-%d")
    result = subprocess.run(
        ["git", "log", "--format=%H %ae %ad", "--date=short",
         f"--since={since}", "--", path],
        capture_output=True, text=True, check=True
    )
    commits = []
    for line in result.stdout.splitlines():
        parts = line.split()
        if len(parts) >= 3:
            commits.append({"hash": parts[0], "author": parts[1], "date": parts[2]})
    return commits


def compute_shadow_coverage(codeowners: dict[str, str], days: int = 90) -> dict:
    """For each CODEOWNERS path, check how many listed owners have recent commits."""
    coverage = {}
    for path, owners_str in codeowners.items():
        owners = [o.lstrip("@") for o in owners_str.split()]
        commits = get_recent_commits(path, days)
        active_authors = {c["author"].split("@")[0] for c in commits}
        covered_owners = [o for o in owners
                          if any(o.lower() in a.lower() for a in active_authors)]
        coverage[path] = {
            "owners": owners,
            "active_in_90d": covered_owners,
            "coverage_pct": len(covered_owners) / len(owners) * 100 if owners else 0
        }
    return coverage


if __name__ == "__main__":
    # Load CODEOWNERS (simplified — real parser handles comments + globs)
    co_entries = {}
    for line in Path(".github/CODEOWNERS").read_text().splitlines():
        line = line.strip()
        if line and not line.startswith("#"):
            parts = line.split()
            if len(parts) >= 2:
                co_entries[parts[0]] = " ".join(parts[1:])

    coverage = compute_shadow_coverage(co_entries)
    uncovered = [(p, d) for p, d in coverage.items() if d["coverage_pct"] < 50]

    if uncovered:
        print(f"WARNING: {len(uncovered)} paths have < 50% owner activity in last 90 days:")
        for path, data in uncovered:
            print(f"  {path}: only {data['active_in_90d']} of {data['owners']} active")
    else:
        print("OK: all CODEOWNERS paths have active reviewers")
